  1→import { generateId } from './ids';
  2→import { WALL_THICKNESS, WALL_HEIGHT, DOOR_WIDTH, DOOR_HEIGHT, DOOR_SILL_HEIGHT, WINDOW_WIDTH, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT, COLUMN_WIDTH, COLUMN_DEPTH, BEAM_WIDTH, BEAM_DEPTH, STAIR_WIDTH, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, SLAB_THICKNESS, SLAB_ELEVATION, SECTION_DEPTH, ROOM_COLOR, DIMENSION_DEFAULT_OFFSET } from './defaults';
  3→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
  4→
  5→export function createProject(name = 'Untitled Project') {
  6→  return {
  7→    id: generateId('proj'),
  8→    name,
  9→    createdAt: new Date().toISOString(),
 10→    updatedAt: new Date().toISOString(),
 11→    floors: [createFloor('Ground Floor', 0)],
 12→    sheets: [],
 13→    version: 1,
 14→  };
 15→}
 16→
 17→export function createFloor(name = 'Floor', level = 0) {
 18→  return {
 19→    id: generateId('floor'),
 20→    name,
 21→    level,
 22→    walls: [],
 23→    rooms: [],
 24→    doors: [],
 25→    windows: [],
 26→    columns: [],
 27→    beams: [],
 28→    stairs: [],
 29→    annotations: [],
 30→    annotationSettings: createAnnotationSettings(),
 31→    slabs: [],
 32→    sectionCuts: [],
 33→  };
 34→}
 35→
 36→export function nextSectionLabel(existingCuts = []) {
 37→  const usedLetters = new Set(
 38→    existingCuts
 39→      .map(c => {
 40→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 41→        return match ? match[1] : null;
 42→      })
 43→      .filter(Boolean)
 44→  );
 45→  for (let i = 0; i < 26; i++) {
 46→    const letter = String.fromCharCode(65 + i);
 47→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 48→  }
 49→  return `Section ${existingCuts.length + 1}`;
 50→}
