149→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}) {
150→  return {
151→    id: generateId('stair'),
152→    startPoint: { x: startPoint.x, y: startPoint.y },
153→    width,
154→    numberOfRisers,
155→    riserHeight,
156→    treadDepth,
157→    direction: {
158→      angle: direction?.angle ?? 0,
159→    },
160→    floorRelation: {
161→      fromFloorId: floorRelation.fromFloorId ?? null,
162→      toFloorId: floorRelation.toFloorId ?? null,
163→    },
164→  };
165→}
