167→export function createSectionCut(startPoint, endPoint, options = {}) {
168→  return {
169→    id: generateId('section'),
170→    startPoint: { x: startPoint.x, y: startPoint.y },
171→    endPoint: { x: endPoint.x, y: endPoint.y },
172→    depth: options.depth ?? SECTION_DEPTH,
173→    label: options.label ?? 'Section A-A',
174→    direction: options.direction ?? 1,
175→  };
176→}
177→
178→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
179→  const area = polygonArea(points);
180→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
181→  return {
182→    id: generateId('room'),
183→    name,
184→    points: points.map(p => ({ x: p.x, y: p.y })),
185→    labelPosition: { ...centroid },
186→    color,
187→    area,
188→  };
189→}
