  1→import { DOOR_HEIGHT, DOOR_SILL_HEIGHT, SLAB_ELEVATION, SLAB_THICKNESS, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH, WALL_HEIGHT, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT } from '@/domain/defaults';
  2→import { createAnnotationSettings } from '@/domain/models';
  3→
  4→export function deserializeProject(json) {
  5→  if (!json || !json.version || !json.data) {
  6→    throw new Error('Invalid project data');
  7→  }
  8→  if (json.version !== 1) {
  9→    throw new Error(`Unsupported project version: ${json.version}`);
 10→  }
 11→
 12→  const project = json.data;
 13→
 14→  // Basic validation
 15→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 16→    throw new Error('Invalid project structure');
 17→  }
 18→
 19→  if (!Array.isArray(project.sheets)) {
 20→    project.sheets = [];
 21→  }
 22→
 23→  for (const floor of project.floors) {
 24→    if (!floor.id || !Array.isArray(floor.walls)) {
 25→      throw new Error('Invalid floor structure');
 26→    }
 27→  }
 28→
 29→  // Backfill missing room fields for old saves
 30→  for (const floor of project.floors) {
 31→    if (!floor.rooms) floor.rooms = [];
 32→    for (const room of floor.rooms) {
 33→      if (!room.points) room.points = [];
 34→      if (room.area === undefined) room.area = 0;
 35→    }
 36→  }
 37→
 38→  // Backfill door/window type fields for old saves
 39→  for (const floor of project.floors) {
 40→    if (!floor.doors) floor.doors = [];
 41→    for (const door of floor.doors) {
 42→      if (!door.type) door.type = 'swing';
 43→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 44→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 45→    }
 46→    if (!floor.windows) floor.windows = [];
 47→    for (const win of floor.windows) {
 48→      if (!win.type) win.type = 'standard';
 49→      if (!win.openDirection) win.openDirection = 'left';
 50→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 51→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 52→    }
 53→    if (!floor.columns) floor.columns = [];
 54→    if (!floor.beams) floor.beams = [];
 55→    if (!floor.stairs) floor.stairs = [];
 56→    if (!floor.annotations) floor.annotations = [];
 57→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 58→    // Migrate single slab → slabs array
 59→    if (floor.slab !== undefined) {
 60→      floor.slabs = floor.slab ? [floor.slab] : [];
 61→      delete floor.slab;
 62→    }
 63→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 64→    // Migrate single sectionCut → sectionCuts array
 65→    if (floor.sectionCut !== undefined) {
 66→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 67→      delete floor.sectionCut;
 68→    }
 69→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 70→    for (const wall of floor.walls) {
 71→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 72→      if (wall.startAttachment === undefined) wall.startAttachment = null;
 73→      if (wall.endAttachment === undefined) wall.endAttachment = null;
 74→    }
 75→    for (const column of floor.columns) {
 76→      if (column.showLabel === undefined) {
 77→        column.showLabel = Boolean(column.name);
 78→      }
 79→    }
 80→    for (const beam of floor.beams) {
 81→      if (beam.floorLevel === undefined) beam.floorLevel = floor.level ?? 0;
 82→    }
 83→    for (const stair of floor.stairs) {
 84→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
 85→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
 86→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
 87→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
 88→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
 89→      if (stair.direction === undefined) {
 90→        stair.direction = { angle: 0 };
 91→      } else if (typeof stair.direction === 'number') {
 92→        stair.direction = { angle: stair.direction };
 93→      } else if (stair.direction.angle === undefined) {
 94→        stair.direction.angle = 0;
 95→      }
 96→      if (stair.floorRelation === undefined) {
 97→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
 98→      } else {
 99→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
100→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
101→      }
102→    }
103→    for (const annotation of floor.annotations) {
104→      if (!annotation.id) {
105→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
106→      }
107→      if (!annotation.type) annotation.type = 'dimension';
108→      if (!annotation.mode) annotation.mode = 'aligned';
109→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
110→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
111→      if (annotation.offset === undefined) annotation.offset = 300;
112→      if (annotation.textOverride === undefined) annotation.textOverride = '';
113→    }
114→    for (const slab of floor.slabs) {
115→      if (!slab.floorId) slab.floorId = floor.id;
116→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
117→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
118→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
119→      if (slab.name === undefined) slab.name = '';
120→      if (slab.type === undefined) slab.type = '';
121→    }
122→    for (const sc of floor.sectionCuts) {
123→      if (!sc.id) {
124→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
125→      }
126→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
127→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
128→      if (sc.depth === undefined) sc.depth = 2000;
129→      if (sc.label === undefined) sc.label = 'Section A-A';
130→      if (sc.direction === undefined) sc.direction = 1;
131→    }
132→  }
133→
134→  for (const sheet of project.sheets) {
135→    if (!sheet.id) {
136→      sheet.id = `sheet_${Math.random().toString(36).slice(2, 8)}`;
137→    }
138→    if (sheet.title === undefined) sheet.title = '';
139→    if (sheet.paperSize === undefined) sheet.paperSize = 'A3_LANDSCAPE';
140→    if (sheet.scaleLabel === undefined) sheet.scaleLabel = '1:100';
141→    if (sheet.drawingName === undefined) sheet.drawingName = sheet.title || 'Drawing';
142→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
143→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
144→
145→    for (const viewport of sheet.viewports) {
146→      if (!viewport.id) {
147→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
148→      }
149→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
150→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = project.floors[0]?.id ?? null;
151→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
152→      if (viewport.x === undefined) viewport.x = 20;
153→      if (viewport.y === undefined) viewport.y = 20;
154→      if (viewport.width === undefined) viewport.width = 160;
155→      if (viewport.height === undefined) viewport.height = 100;
156→      if (viewport.scale === undefined) viewport.scale = 100;
157→      if (viewport.title === undefined) viewport.title = '';
158→      if (viewport.rotation === undefined) viewport.rotation = 0;
159→    }
160→  }
161→
162→  return { project, savedAt: json.savedAt };
163→}
