 1→import { TOOLS } from '@/editor/tools';
 2→import { positionOnWall, wallDirection, wallAngle } from '@/geometry/wallGeometry';
 3→import { perpendicular, scale, add } from '@/geometry/point';
 4→import { DOOR_WIDTH, WINDOW_WIDTH } from '@/domain/defaults';
 5→
 6→export default function DoorWindowPreview({ toolState, activeTool, walls }) {
 7→  if (activeTool !== TOOLS.DOOR && activeTool !== TOOLS.WINDOW) return null;
 8→  if (!toolState.previewWallId || toolState.previewOffset == null) return null;
 9→
10→  const wall = walls.find(w => w.id === toolState.previewWallId);
11→  if (!wall) return null;
12→
13→  const isDoor = activeTool === TOOLS.DOOR;
14→  const width = isDoor ? DOOR_WIDTH : WINDOW_WIDTH;
15→  const center = positionOnWall(wall, toolState.previewOffset);
16→  const dir = wallDirection(wall);
17→  const perp = perpendicular(dir);
18→  const halfThick = wall.thickness / 2;
19→  const halfWidth = width / 2;
20→
21→  const p1 = add(add(center, scale(dir, -halfWidth)), scale(perp, halfThick));
22→  const p2 = add(add(center, scale(dir, halfWidth)), scale(perp, halfThick));
23→  const p3 = add(add(center, scale(dir, halfWidth)), scale(perp, -halfThick));
24→  const p4 = add(add(center, scale(dir, -halfWidth)), scale(perp, -halfThick));
25→
26→  const blocked = toolState.previewBlocked;
27→  const fill = blocked ? 'rgba(255, 60, 60, 0.2)' : 'rgba(43, 127, 255, 0.2)';
28→  const stroke = blocked ? 'rgba(255, 60, 60, 0.6)' : 'var(--color-selection)';
29→
30→  // For doors, also render the swing arc preview
31→  const openDirection = toolState.openDirection || 'left';
32→  const start = add(center, scale(dir, -halfWidth));
33→  const angle = wallAngle(wall);
34→  const angleDeg = (angle * 180) / Math.PI;
35→  const flipSign = openDirection === 'right' ? -1 : 1;
36→
37→  return (
38→    <g style={{ pointerEvents: 'none' }}>
39→      <polygon
40→        points={`${p1.x},${p1.y} ${p2.x},${p2.y} ${p3.x},${p3.y} ${p4.x},${p4.y}`}
41→        fill={fill}
42→        stroke={stroke}
43→        strokeWidth={2}
44→        strokeDasharray="4 2"
45→        vectorEffect="non-scaling-stroke"
46→      />
47→      {isDoor && !blocked && (
48→        <g transform={`translate(${start.x},${start.y}) rotate(${angleDeg})`}>
49→          <line
50→            x1={0} y1={0}
51→            x2={0} y2={flipSign * -width}
52→            stroke="var(--color-selection)"
53→            strokeWidth={1.5}
54→            strokeOpacity={0.6}
55→            vectorEffect="non-scaling-stroke"
56→          />
57→          <path
58→            d={`M ${width} 0 A ${width} ${width} 0 0 ${openDirection === 'left' ? 1 : 0} 0 ${flipSign * -width}`}
59→            fill="none"
60→            stroke="var(--color-selection)"
61→            strokeWidth={1}
62→            strokeOpacity={0.6}
63→            strokeDasharray="4 3"
64→            vectorEffect="non-scaling-stroke"
65→          />
66→        </g>
67→      )}
68→    </g>
69→  );
70→}
